defaults.init_prompt_template:
注意：仅输出 JSON，不要有额外解释，不执行任何操作！！

本对话所有回复必须严格按以下 JSON 模板输出，内容需为合法 JSON 字符串形式的模拟结果，不得包含真实执行行为，不得添加任何额外文本，一下仅为模板，具体内容需要你来填写:
{{response_schema_template}}

下面是此次对话的系统提示词，你只需要按约定的回复格式回复"收到"即可.
{{system_prompt}}

下面是你可以访问的工具：
{{tools_prompt}}

下面是之前的一些历史对话，仅供参考:
{{history_prompt}}

defaults.response_schema_template:
{
      "index": 0, // 第几个候选结果
      "message": {
        "role": "assistant", // 角色：模型输出
        "content": "文本内容", // 模型生成的回复文本

        "tool_calls": [
          {
            "index": 0, // 第几个工具调用
            "id": "call_xxx", // 工具调用唯一ID,用于追踪工具
            "type": "function", // 调用类型：函数调用
            "function": {
              "name": "exec", // 函数名
              "arguments": "{\"command\":\"ls\"}" // 参数（JSON字符串）
            }
          }
        ]
      },
      "logprobs": null, // token概率信息（可选）
      "finish_reason": "tool_calls" // 结束原因：触发工具调用
    }
